// Function to validate HTML anchor tags
function validateTags(tags) {
    let result = [];
    for (let tag of tags) {
        let regex = /<a href=(.*?)( target=(.*?))>/;
        let match = regex.exec(tag);
        if (match) {
            result.push(tag);
        } else {
            let text = tag.match(/^<a(.*?)>/)[1].trim();
            result.push(tag.replace(/<a(.*?)>/, '<a href=' + text + ' target=_blank>'));
        }
    }
    return result;
}

